\begin{proof}
Write $\bm{\hat a}=(\hat a_1,\dots,\hat a_m)^{\mathsf T}$. The Heisenberg equation generated by $H_{\rm DPLO}$ is the
forced linear system
\begin{equation}
\label{eq:DPLO_heis}
\frac{d}{ds}\bm{\hat a}(s)=i[H_{\rm DPLO},\bm{\hat a}(s)]=-iK\,\bm{\hat a}(s)-i\bm{\eta}.
\end{equation}
Solving it gives an affine Heisenberg map
\begin{equation}
\label{eq:DPLO_affine}
U_{\rm DPLO}^\dagger(t)\,\bm{\hat a}\,U_{\rm DPLO}(t)=S(t)\bm{\hat a}+\bm{\gamma}(t),
\qquad
S(t)=e^{-iKt},
\qquad
\bm{\gamma}(t)=-i\int_{0}^{t} e^{-iK(t-s)}\,\bm{\eta}\,ds.
\end{equation}

Now fix a product coherent state
\begin{equation}
\ket{\bm{\alpha}}:=\ket{\alpha^{(1)}}\otimes\cdots\otimes\ket{\alpha^{(m)}},
\qquad
\bm{\alpha}=(\alpha^{(1)},\dots,\alpha^{(m)})^{\mathsf T},
\end{equation}
so that $\bm{\hat a}\ket{\bm{\alpha}}=\bm{\alpha}\ket{\bm{\alpha}}$. Using Eq.~\eqref{eq:DPLO_affine},
\begin{equation}
\bm{\hat a}\,U_{\rm DPLO}(t)\ket{\bm{\alpha}}
=
U_{\rm DPLO}(t)\,\bigl(S(t)\bm{\hat a}+\bm{\gamma}(t)\bigr)\ket{\bm{\alpha}}
=
\bigl(S(t)\bm{\alpha}+\bm{\gamma}(t)\bigr)\,U_{\rm DPLO}(t)\ket{\bm{\alpha}}.
\end{equation}
Thus $U_{\rm DPLO}(t)\ket{\bm{\alpha}}$ is a joint eigenvector of $\bm{\hat a}$ with eigenvalue
$\bm{\alpha}'=S(t)\bm{\alpha}+\bm{\gamma}(t)$, hence
\begin{equation}
\label{eq:DPLO_coherent_map}
U_{\rm DPLO}(t)\ket{\bm{\alpha}}=e^{i\phi(\bm{\alpha};t)}\ket{\bm{\alpha}'}
\end{equation}
for some phase $\phi(\bm{\alpha};t)$. Writing $\bm{\beta}:=S(t)\bm{\alpha}$, the $\bm{\alpha}$-dependent part of this
phase can be taken in the standard displacement form,
\begin{equation}
\label{eq:DPLO_phase}
e^{i\phi(\bm{\alpha};t)}
=
e^{i\chi(t)}\,
\exp\!\Big(\frac{1}{2}\big(\bm{\gamma}(t)\!\cdot\!\bm{\beta}^*-\bm{\gamma}(t)^*\!\cdot\!\bm{\beta}\big)\Big),
\end{equation}
where $\chi(t)$ is independent of $\bm{\alpha}$ (and therefore contributes only a global phase when acting on a
superposition).

Finally, apply Eq.~\eqref{eq:DPLO_coherent_map} to each coherent-product term in Eq.~\eqref{eq:cs-ansatz}. Each input
term produces exactly one output coherent-product term, with updated amplitudes
$\bm{\alpha}_k' = S(t)\bm{\alpha}_k+\bm{\gamma}(t)$ and updated coefficient obtained by multiplying $C_k$ by the
$k$-dependent phase factor in Eq.~\eqref{eq:DPLO_phase} (the common factor $e^{i\chi(t)}$ is a global phase). Hence the number
of terms $N$ is unchanged.
\end{proof}

