\begin{proof}
The DPLO update has the affine form
\begin{equation}
    \bm{\alpha}\mapsto S_\ell\bm{\alpha}+\bm{\gamma}^{(\ell)},
    \qquad
    S_\ell^\dagger S_\ell=I .
\end{equation}
Therefore
\begin{equation}
    \|S_\ell\bm{\alpha}+\bm{\gamma}^{(\ell)}\|_2
    \le
    \|\bm{\alpha}\|_2+\|\bm{\gamma}^{(\ell)}\|_2 .
\end{equation}
Iterating this inequality over all layers gives
\begin{equation}
    \|\bm{\alpha}\|_2
    \le
    A_{\rm in}
    +
    \sum_{\ell=1}^L
    \|\bm{\gamma}^{(\ell)}\|_2
    =
    A_{\rm in}+\Gamma .
\end{equation}
Thus every first-mode amplitude encountered before a Kerr update obeys
\begin{equation}
    |\alpha^{(1)}|
    \le
    A_{\rm in}+\Gamma .
\end{equation}

We choose the local Kerr reconstruction error to be
\begin{equation}
    \eta:=\frac{\varepsilon}{L}.
\end{equation}
By Theorem~\ref{thm:kerr-coherent-expansion},
Lemma~\ref{thm:kerr-coherent-truncation}, and
Lemma~\ref{lem:fock-to-coherent-switch}, it is sufficient to choose the
cutoff so that, uniformly for all
$|\alpha|\le A_{\rm in}+\Gamma$,
\begin{equation}
    \big\|
        K_{\kappa_\ell}\ket{\alpha}
        -
        \ket{\phi_{\alpha,\kappa_\ell}^{(N_F)}}
    \big\|_2
    \le
    \eta,
\end{equation}
where $ \ket{\phi_{\alpha,\kappa_\ell}^{(N_F)}}$ is given in \eqref{eq:phi-final}. Using the Poisson-tail bound and the coherent-grid leakage bound, a
sufficient choice is
\begin{equation}
    N_F
    =
    O\!\left(
        (A_{\rm in}+\Gamma)^2
        +
        \sqrt{(A_{\rm in}+\Gamma)^2\log(1/\eta)}
        +
        \log(1/\eta)
    \right).
\end{equation}
Since $\eta=\varepsilon/L$, this becomes
\begin{equation}
    N_F
    =
    O\!\left(
        (A_{\rm in}+\Gamma)^2
        +
        \sqrt{(A_{\rm in}+\Gamma)^2\log(L/\varepsilon)}
        +
        \log(L/\varepsilon)
    \right).
\end{equation}

It remains to compose the local errors. Let
\begin{equation}
    V_\ell
    :=
    K_{\kappa_\ell}^{(1)}
    U_{\mathrm{DPLO}}^{(\ell)},
    \qquad
    \widetilde V_\ell
    :=
    \widetilde K_{\kappa_\ell,N_F}^{(1)}
    U_{\mathrm{DPLO}}^{(\ell)}
\end{equation}
be the exact and approximate one-layer maps. The telescopic identity gives
\begin{equation}
    V_L\cdots V_1
    -
    \widetilde V_L\cdots \widetilde V_1
    =
    \sum_{\ell=1}^L
    V_L\cdots V_{\ell+1}
    \big(
        V_\ell-\widetilde V_\ell
    \big)
    \widetilde V_{\ell-1}\cdots \widetilde V_1 .
\end{equation}
Applying this identity to $\ket{\psi_0}$ and taking the Hilbert-space
norm,
\begin{equation}
\begin{aligned}
    \big\|
        V_L\cdots V_1\ket{\psi_0}
        -
        \widetilde V_L\cdots\widetilde V_1\ket{\psi_0}
    \big\|_2
    &\le
    \sum_{\ell=1}^L
    \left\|
        V_L\cdots V_{\ell+1}
        \big(
            V_\ell-\widetilde V_\ell
        \big)
        \widetilde V_{\ell-1}\cdots\widetilde V_1
        \ket{\psi_0}
    \right\|_2 .
\end{aligned}
\end{equation}
The exact layers $V_L,\dots,V_{\ell+1}$ are unitary, so they do not
change the norm. By construction, each remaining summand is at most
$\eta=\varepsilon/L$. Hence
\begin{equation}
    \big\|
        V_L\cdots V_1\ket{\psi_0}
        -
        \widetilde V_L\cdots\widetilde V_1\ket{\psi_0}
    \big\|_2
    \le
    \sum_{\ell=1}^L\frac{\varepsilon}{L}
    =
    \varepsilon .
\end{equation}
The final Gaussian unitary $U_G$ is common to both evolutions and is
unitary, so it preserves the distance.

Finally, each Kerr reconstruction replaces one coherent-product
component by at most $N_F+1$ coherent-product components. Thus
\begin{equation}
    N_L
    \le
    N_0(N_F+1)^L .
\end{equation}
The DPLO update costs $O(m^3)$ per layer to compute the matrix
exponential and displacement vector, and $O(m^2)$ per propagated
coherent-product component. Therefore
\begin{equation}
    \mathrm{FLOPs}_{\mathrm{forward}}
    =
    O\!\left(
        Lm^3
        +
        m^2N_0(N_F+1)^L
    \right),
\end{equation}
up to factors polynomial in $N_F$ for evaluating the coherent-grid
coefficients.
\end{proof}

