\begin{proof}
Expanding Eq.~\eqref{eq:psi2-theta-def} in the Fock basis, we obtain
\begin{equation}
\label{eq:psi2-fock-expansion}
\ket{\psi_2(\theta)}
=
e^{-\lambda/2}\sum_{n=0}^{\infty}\frac{\alpha^n}{\sqrt{n!}}
\begin{cases}
\ket n, & n \text{ even},\\[2mm]
e^{i\theta}\ket n, & n \text{ odd},
\end{cases}
\qquad \lambda:=|\alpha|^2.
\end{equation}

On the other hand, the exact Kerr-evolved coherent state is
\begin{equation}
\label{eq:kerr-coherent}
K_\kappa\ket{\alpha}
=
e^{-\lambda/2}\sum_{n=0}^{\infty}\frac{\alpha^n}{\sqrt{n!}}\,e^{i\kappa n^2}\ket n.
\end{equation}

Therefore, by orthogonality of the Fock basis,
\begin{equation}
\label{eq:norm-split}
\begin{aligned}
\left\|K_\kappa\ket{\alpha}-\ket{\psi_2(\theta)}\right\|_2^2
={}&
e^{-\lambda}\sum_{n\,\mathrm{even}}\frac{\lambda^n}{n!}\,\bigl|e^{i\kappa n^2}-1\bigr|^2
\\
&+
e^{-\lambda}\sum_{n\,\mathrm{odd}}\frac{\lambda^n}{n!}\,\bigl|e^{i\kappa n^2}-e^{i\theta}\bigr|^2.
\end{aligned}
\end{equation}

Using
\begin{equation}
\label{eq:trig-ineq}
|e^{ix}-e^{iy}|^2
=
4\sin^2\!\left(\frac{x-y}{2}\right)
\le (x-y)^2,
\qquad x,y\in\mathbb R,
\end{equation}
we obtain
\begin{equation}
\label{eq:after-bound}
\left\|K_\kappa\ket{\alpha}-\ket{\psi_2(\theta)}\right\|_2^2
\le
e^{-\lambda}\sum_{n\,\mathrm{even}}\frac{\lambda^n}{n!}\,\kappa^2 n^4
+
e^{-\lambda}\sum_{n\,\mathrm{odd}}\frac{\lambda^n}{n!}\,(\kappa n^2-\theta)^2.
\end{equation}

Expanding the square in the odd sector yields
\begin{equation}
\label{eq:expand}
\begin{aligned}
\left\|K_\kappa\ket{\alpha}-\ket{\psi_2(\theta)}\right\|_2^2
\le\;&
e^{-\lambda}\sum_{n\,\mathrm{even}}\frac{\lambda^n}{n!}\,\kappa^2 n^4
\\
&+
e^{-\lambda}\sum_{n\,\mathrm{odd}}\frac{\lambda^n}{n!}\,
\bigl(\kappa^2 n^4-2\kappa\theta n^2+\theta^2\bigr)
\\[2mm]
=\;&
\kappa^2 e^{-\lambda}\sum_{n=0}^{\infty}\frac{\lambda^n}{n!}\,n^4
-2\kappa\theta\, e^{-\lambda}\sum_{n\,\mathrm{odd}}\frac{\lambda^n}{n!}\,n^2
+\theta^2 e^{-\lambda}\sum_{n\,\mathrm{odd}}\frac{\lambda^n}{n!}.
\end{aligned}
\end{equation}

Now let \(M\) be distributed according to the Poisson distribution with parameter \(\lambda\), i.e.
$M\sim\mathrm{Pois}(\lambda)$.
Then Eq.~\eqref{eq:expand} can be rewritten as
\begin{equation}
\label{eq:prob-form}
\left\|K_\kappa\ket{\alpha}-\ket{\psi_2(\theta)}\right\|_2^2
\le
\kappa^2\,\mathbb E[M^4]
-2\kappa\theta\,\mathbb E\!\left[M^2\mathbf 1_{\mathrm{odd}}(M)\right]
+\theta^2\,\mathbb P(M\text{ odd}).
\end{equation}

Using the standard Poisson identities
\begin{equation}
\label{eq:m4}
\mathbb E[M^4]=\lambda^4+6\lambda^3+7\lambda^2+\lambda,
\end{equation}
\begin{equation}
\label{eq:odd-prob}
\mathbb P(M\text{ odd})=\frac{1-e^{-2\lambda}}{2},
\end{equation}
and
\begin{equation}
\label{eq:odd-moment}
\mathbb E\!\left[M^2\mathbf 1_{\mathrm{odd}}(M)\right]
=
\frac12\Bigl((\lambda^2+\lambda)-e^{-2\lambda}(\lambda^2-\lambda)\Bigr),
\end{equation}
we obtain
\begin{equation}
\label{eq:final}
\begin{aligned}
\left\|K_\kappa\ket{\alpha}-\ket{\psi_2(\theta)}\right\|_2^2
\le\;&
\kappa^2\bigl(\lambda^4+6\lambda^3+7\lambda^2+\lambda\bigr)
\\
&\;
-\kappa\theta\Bigl((\lambda^2+\lambda)-e^{-2\lambda}(\lambda^2-\lambda)\Bigr)
+\frac{\theta^2}{2}\bigl(1-e^{-2\lambda}\bigr),
\end{aligned}
\end{equation}
which is exactly Eq.~\eqref{eq:L1-general-theta-bound}.
\end{proof}

