\end{equation}
Then it is enough to solve
\begin{equation}
\label{eq:proof-thm-online-s-lambert-start}
c\left(\frac{a}{s}\right)^s\le \Delta_\epsilon,
\end{equation}
or equivalently
\begin{equation}
\label{eq:proof-thm-online-s-lambert-log}
s\log\!\left(\frac{s}{a}\right)\ge \log\!\left(\frac{c}{\Delta_\epsilon}\right).
\end{equation}
Writing $M:=\log\!\left(\frac{c}{\Delta_\epsilon}\right)$ and setting $s=a e^u$, we obtain $aue^u=M$, hence
$u=W(M/a)$, where $W$ denotes the Lambert $W$ function \cite{Corless1996}. Therefore
\begin{equation}
\label{eq:proof-thm-online-s-lambert-explicit}
s
=
a e^{W(M/a)}
=
\frac{M}{W(M/a)}.
\end{equation}
