\begin{equation}
\label{eq:proof-thm-online-s-asymptotic}
s
=
\Theta\left(
\frac{\log\left(\frac{1}{\epsilon-E_0}\right)}
{\log\log\!\big(\frac{1}{\epsilon-E_0}\big)}
\right),
\end{equation}
which is exactly Eq.~\eqref{eq:s-loglog-scaling-final-eps}.

