\begin{equation}
\label{eq:proof-thm-online-runtime-one-layer}
\mathcal{O}(m^3+m^2N_q).
\end{equation}
By Eq.~\eqref{eq:thm-online-small-kappa-term-count}, we have
\begin{equation}
\label{eq:proof-thm-online-runtime-branches}
