\qquad q=0,\dots,L.
\end{equation}
Therefore the total propagation cost through all $L$ layers is
\begin{equation}
\label{eq:proof-thm-online-runtime-total}
\sum_{q=1}^{L}\mathcal{O}(m^3+m^2N_q)
=
\mathcal{O}\!\left(Lm^3+m^2\sum_{q=1}^{L}q^s\right)
=
\mathcal{O}(Lm^3+m^2L^{s+1}).
\end{equation}
