\begin{equation}
6\lambda^3\le 3\lambda^4+3\lambda^2,
\qquad
\lambda\le 1+\lambda^2,
\end{equation}
so
\begin{equation}
\lambda^4+6\lambda^3+7\lambda^2+\lambda
\le
4\lambda^4+11\lambda^2+1
\le
16(1+\lambda^2)^2.
\end{equation}
